/*
 * Главный файл стилей.
 * Все паршалы подключаются сюда.
 */

// Стили для файла с примером HTML-фрагмента
@import './utils/variables';
@import './utils/visually-hidden';

@import './base/common';
@import './base/container';

@import './components/page-logo';

@import './layout/page-header';
@import './layout/page-footer';
@import './layout/page-hero';
@import './layout/our-features';
@import './layout/we-solve';
@import './layout/how-we-do-it';
@import './layout/our-program';
@import './layout/teacher';
@import './layout/we-promise';
@import './layout/feedbacks';

@import './components/backdrop';

