.our-program{
    padding-top: 50px;
    padding-bottom: 370px;
    background-color: var(--main-color);
  }

.our-program .container{
    position: relative;
}

.our-program-title{
    margin-bottom: 43px;
    font-weight: 800;
    font-size: 20px;
    line-height: 1.3;
    letter-spacing: 0.03em;

    text-align: center;

    color: var(--white-color);
}

.our-program-list{
    margin-left: 105px;
    margin-bottom: 50px;

    &::before{
        display: inline-block;
        content: "";
        position: absolute;
        left: 79px;
        top: 82px;
        width: 1px;
        height: 1282px;
        background-color: var(--white-color);
    }
}

.our-program-item{
    position: relative;
    font-weight: 700;
    font-size: 14px;
    line-height: 2;
    letter-spacing: 0.08em;
    text-transform: uppercase;

    color: var(--white-color);
    
    &:not(:last-child){
        margin-bottom: 40px;
    }

    &::before{
        display: flex;
        position: absolute;
        left: -51px;
        top: 6px;
        content: "";
        width: 12px;
        height: 12px;

        background-color: var(--orange-color);
        border-radius: 50%;
    }
}

.our-program-semester-list{
    margin-top: 13px;
}

.our-program-semester-item{
    position: relative;
    font-weight: 700;
    font-size: 12px;
    line-height: 1.667;
    letter-spacing: 0.08em;
    text-transform: none;

    color: var(--orange-color);

    &:not(:last-child){
        margin-bottom: 11px;
    }

}

.our-program-semester-text{
  margin-left: 20px;

  &::before{
    position: absolute;
    content: "";
    width: 13px;
    height: 1px;
    top: 9px;
    left: 0;
    background-color: var(--orange-color);
  }
}

.our-program-semester-empty{
  content: '';
  height: 20px;
  width: 1px;

  &::before{
    position: absolute;
    content: "";
    width: 13px;
    height: 1px;
    top: 40px;
    left: 0;
    background-color: var(--orange-color);
  }

}

.our-program-topic-list{
    margin-top: 11px;
}

.our-program-topic-item{
    font-weight: 500;
    font-size: 12px;
    line-height: 1.667;
    letter-spacing: 0.08em;
    text-transform: none;

    color: var(--grey-color);

    opacity: 0.5;
}

.our-program-bg{
  position: absolute;
  top: 1405px;
  left: 200px;
  background-image: url('../images/our-program/bg-our-program-mobile.png');
  background-repeat: no-repeat;
  background-size: cover;
  height: 136px;
  width: 176px;
  overflow: hidden;
}

