    background-color: var(--white-color);
    box-shadow: -5px 8px 26px rgba(0, 0, 0, 0.04);

    @media screen and (min-width: 768px) {
      max-width: 688px;
      
      display: flex;

      margin-top: 30px;
      padding: 40px;

      position: relative;
   }

   @media screen and (min-width: 1344px) {
    max-width: 1090px;

    margin-left: auto;
    margin-right: auto;

    padding: 50px 112px 51px 82px;
  }
  
    & .reviews-image {
      width: 90px;
      height: 90px;
  
      margin-left: auto;
      margin-right: auto;

      @media screen and (min-width: 768px) {
