        color: var(--orange-color);

        @media screen and (min-width: 768px) {
          margin-top: 0;

          text-align: start;

          font-size: 20px;
          line-height: 1.2;
      }

        @media screen and (min-width: 1344px) {
          font-size: 30px;
          line-height: 1.233;
      }
