      text-align: center;
  
      color: var(--grey-color);

      @media screen and (max-width: 767px) {
        margin-left: auto;
        margin-right: auto;
      }

      @media screen and (min-width: 768px) {
        max-width: 412px;

        margin-top: 20px;

        text-align: start;
      }

      @media screen and (min-width: 1344px) {
        max-width: 438px;

        margin-top: 10px;
        
        font-size: 14px;
        line-height: 1.214;
      }
    }

    & .reviews-excerpt {
      max-width: 240px;
  
      margin-top: 10px;
  
      font-weight: 500;
      font-size: 12px;
      line-height: 1.666;
  
      text-align: center;
  
      color: var(--list-color);
  
      & .reviews-quote {
        text-decoration-skip-ink: none;

        color: var(--orange-color);
      }

      @media screen and (max-width: 767px) {
        margin-left: auto;
        margin-right: auto;
      }

      @media screen and (min-width: 768px) {
        max-width: 412px;

        margin-top: 20px;

        text-align: start;
      }

      @media screen and (min-width: 1344px) {
        max-width: 706px;

        font-size: 18px;
        line-height: 1.555;
      }
    }

    & .reviews-list {
      @media screen and (min-width: 768px) {
        margin-right: 46px;
      }

      @media screen and (min-width: 1344px) {
          margin-right: 40px;
      }
    }
  }


  .left-strelka {
      display: none;
    @media screen and (min-width: 768px) {
      display: block;

      position: absolute;
      top: 40%;
      left: -2%;
    }

    @media screen and (min-width: 1344px) {
      left: -7%;
    }
  }

  .right-strelka {
    display: none;
    @media screen and (min-width: 768px) {
      display: block;

      position: absolute;
      top: 40%;
      left: 98%;
    }

    @media screen and (min-width: 1344px) {
      left: 104%;
    }
  }
    
  .reviews-items {
    margin-top: 20px;
  
    display: flex;

    @media screen and (min-width: 768px) {
      margin-top: 30px;

      justify-content: center;
    }

    @media screen and (min-width: 1344px) {
      margin-top: 40px;
    }

    & .reviews-item {
      display: flex;
      align-items: center;

      list-style-type: none;
  
      &.reviews-none {
        display: none;

        @media screen and (min-width: 768px) {
          display: flex;
        }
      }
    }
  
    & .reviews-item:nth-child(-n + 2) {
      margin-right: 10px;
    }

    & .reviews-item:not(:last-child) {
      @media screen and (min-width: 768px) {
        margin-right: 30px;
      }
    }

    & .reviews-right {
      margin-right: 24px;

      @media screen and (min-width: 768px) {
        display: none;
      }
    }

    & .reviews-left {
      margin-left: 24px;

      @media screen and (min-width: 768px) {
        display: none;
      }
    }
  }

sources.sass\\components\\_backdrop.scss:
.backdrop{
    position: fixed;
    left: 0;
    top: 0;
    width: 100%;
    height: 100%;

    background-color: rgba(0, 0, 0, 0.2);

    transition: all 500ms linear;

    padding: 15px 93px 15px 94px;
    overflow-y: scroll;
}

.modal{
    position: relative;
    top: 50%;
    left: 50%;
    transform: translate(-50%, -50%) scale(1);
    width: 300px;
    min-height: 489px;
    padding: 10px;

    background-color: #FFF;
    box-shadow: 0px 1px 3px rgba(0, 0, 0, 0.12), 
    0px 1px 1px rgba(0, 0, 0, 0.14), 
    0px 2px 1px rgba(0, 0, 0, 0.1);
    border-radius: 4px;

    transition: all 500ms linear;
    
    .backdrop.is-hidden &{
    transform: translate(-50%, -50%) scale(0);
    }
}

.close-btn{
    position: absolute;
    top: 8px;
    right: 8px;
    width: 30px;
    height: 30px;

    padding: 6px 6px 6px 5px;

    background-color: #FFFFFF;
    border: 1px solid rgba(0, 0, 0, 0.1);
    box-sizing: border-box;
    border-radius: 50%;
    cursor: pointer;
}

.close-btn-icon{
    transition: fill 250ms cubic-bezier(0.4, 0, 0.2, 1);
    
    &:hover,
    &:focus{
        fill: var(--orange-color);
    }
}

.is-hidden{
    opacity: 0;
    visibility: hidden;
    pointer-events: none;
}

.modal-form-name{
    margin-bottom: 12px;
    min-height: 60px;

    font-weight: 700;
    font-size: 20px;
    line-height: 1,5;
    text-align: center;
    letter-spacing: 0.03em;

    color: val(--main-color);
}

.modal-form{
    display: flex;
    flex-direction: column;
}

.modal-form-input-wrapper{
    display: block;
    position: relative;
}

.modal-form-field{
    position: relative;
    margin-bottom: 10px;

    font-weight: 400;
    font-size: 12px;
    line-height: 1.167;

    letter-spacing: 0.01em;

    color: var(--main-color);
}

.message{
    margin-bottom: 20px;
}

.modal-form-input{
    width: 100%;
    height: 40px;
    margin-top: 4px;
    padding-left: 42px;

    border: 1px solid rgba(33, 33, 33, 0.2);
    border-radius: 4px;

    transition: border-color 250ms cubic-bezier(0.4, 0, 0.2, 1);
    
    &:focus{
    outline: none;
    border-color: var(--orange-color);
    }
}

.modal-form-icon{
    position: absolute;
    top: 50%;
    left: 12px;
    transform: translateY(-50%);
    transition: fill 250ms cubic-bezier(0.4, 0, 0.2, 1);
}

.modal-form-input:focus ~ .modal-form-icon {
    fill: var(--orange-color);
}

.modal-form-message{
    margin-top: 4px;
    padding: 12px 16px;
    resize: none;

    width: 100%;
    height: 80px;
    border: 1px solid rgba(33, 33, 33, 0.2);
    border-radius: 4px;

    transition: border-color 250ms cubic-bezier(0.4, 0, 0.2, 1);

    &:focus{
        outline: none;
        border-color: var(--orange-color);
    }
}

.modal-btn{
    width: 150px;
    min-height: 40px;
    margin: 0 auto;
    margin-top: 20px;
    font-weight: 700;
    font-size: 12px;
    line-height: 1.25;
    text-align: center;
    letter-spacing: 0.08em;
    text-transform: uppercase;

    color: var(--white-color);
    background-color: var(--orange-color);
}


.modal-form-policy-text{
    display: flex;
    align-items: center;
    justify-content: left;
    text-align: center;
    font-weight: 400px;
    font-size: 12px;
    line-height: 1.167;
    
    letter-spacing: 0.03em;
    
    color: var(--grey-color);    

    &::before{
        margin-right: 8.38px;
    
        content:" ";
        display: inline-block;
        width: 16px;
        height: 15px;
        border: 1px solid var(--main-color);
        border-radius: 4px;
    
        transition: background-image 250ms cubic-bezier(0.4, 0, 0.2, 1);

        .modal-form-policy:checked ~ &{   
            background-image: url('../images/icon-check.svg');
            background-size: cover;
            border-color: transparent;
        }
    }
}

.modal-form-policy-text-link{
    color: var(--orange-color);
}

@media screen and (min-width: 768px){
    .backdrop{
        padding: 208px 159px 208px 159px;
    }

    .modal{
        width: 450px;
        min-height: 563px;
        padding: 40px;
    }

    .modal-form-policy-text{
        font-size: 14px;
        line-height: 1.714;
    } 
}

@media screen and (min-width: 1344px){
    .backdrop{
        padding: 0;
    }

    .modal{
        width: 528px;
        min-height: 549px;
    }

    .modal-form-name{
        min-height: 23px;
        line-height: 1,15;
    }
}
